617: 		// Setup OpenAPI security: all APIs will have the same authentication for now.
618: 		config.DefaultSecurity = []map[string][]string{}
619: 		keys := []string{}
620: 		for k := range *config.SecurityDefinitions {
621: 			keys = append(keys, k)
622: 		}
623: 		sort.Strings(keys)
624: 		for _, k := range keys {
625: 			config.DefaultSecurity = append(config.DefaultSecurity, map[string][]string{k: {}})
