633: 					Description: "Unauthorized",
634: 				},
635: 			}
636: 		}
637: 	}
638: 	// make sure we populate info, and info.version, if not manually set
639: 	if config.Info == nil {
640: 		config.Info = &spec.Info{}
641: 	}
642: 	if config.Info.Version == "" {
643: 		if version != nil {
644: 			config.Info.Version = strings.Split(version.String(), "-")[0]
645: 		} else {
646: 			config.Info.Version = "unversioned"
647: 		}
648: 	}
649: }
