ivalentResourceRegistryWithIdentity(func(groupResource schema.GroupResource) string {\n739: \t\t\t\t// use the storage prefix as the key if possible\n740: \t\t\t\tif opts, err := c.RESTOptionsGetter.GetRESTOptions(groupResource, nil); err == nil {\n741: \t\t\t\t\treturn opts.ResourcePrefix\n742: \t\t\t\t}\n743: \t\t\t\t// otherwise return \"\" to use the default key (parent GV name)\n744: \t\t\t\treturn \"\"\n745: \t\t\t})\n746: \t\t}\n747: \t}\n748: \n749: \treturn CompletedConfig{\u0026completedConfig{c, informers}}\n750: }\n751: \n752: // Complete fills in any fields not set that are required to have valid data and can be derived\n753: // from other fields. If you're going to `ApplyOptions`, do that first. It's mutating the receiver.\n754: func (c *RecommendedConfig) Complete() CompletedConfig {\n755: \treturn c.Config.Complete(c.SharedInformerFactory)\n756: }\n757: \n758: var defaultAllowedMediaTypes = []string{\n759: \truntime.ContentTypeJSON,\n760: \truntime.ContentTypeYAML,\n761: \truntime.ContentTypeProtobuf,\n762: }\n763: \n764: // New creates a new server which logically combines the handling chain with the passed server.\n765: // name is used to differentiate for logging. The handler chain in particular can be difficult as it starts delegating.\n766: // delegationTarget may not be nil.\n767: func (c completedConfig) New(name string, delegationTarget DelegationTarget) (*GenericAPIServer, error) {\n768: \tif c.Serializer == nil {\n769: \t\treturn nil, fmt.Errorf(\"Genericapiserver.New() called with config.Serializer == nil\")\n770: \t}\n771: \tallowedMediaTypes := defaultAllowedMediaTypes\n772: \tif utilfeature.DefaultFeatureGate.Enabled(genericfeatures.CBORServingAndStorage) {\n773: \t\tallowedMediaTypes = append(allowedMediaTypes, runtime.ContentTypeCBOR)\n774: \t}\n775: \tfor _, info := range c.Serializer.SupportedMediaTypes() {\n776: \t\tvar ok bool\n777: \t\tfor _, mt := range allowedMediaTypes {\n778: \t\t\tif info.MediaType == mt {\n779: \t\t\t\tok =