814: 		EquivalentResourceRegistry:     c.EquivalentResourceRegistry,
815: 		NonLongRunningRequestWaitGroup: c.NonLongRunningRequestWaitGroup,
816: 		WatchRequestWaitGroup:          c.WatchRequestWaitGroup,
817: 		Handler:                        apiServerHandler,
818: 		UnprotectedDebugSocket:         debugSocket,
819: 
820: 		listedPathProvider: apiServerHandler,
821: 
822: 		minRequestTimeout:                   time.Duration(c.MinRequestTimeout) * time.Second,
823: 		ShutdownTimeout:                     c.RequestTimeout,
824: 		ShutdownDelayDuration:               c.ShutdownDelayDuration,
825: 		ShutdownWatchTerminationGracePeriod: c.ShutdownWatchTerminationGracePeriod,
826: 		SecureServingInfo:                   c.SecureServing,
827: 		ExternalAddress:                     c.ExternalAddress,
828: 
829: 		openAPIConfig:           c.OpenAPIConfig,
830: 		openAPIV3Config:         c.OpenAPIV3Config,
831: 		skipOpenAPIInstallation: c.SkipOpenAPIInstallation,
832: 
833: 		postStartHooks:         map[string]postStartHookEntry{},
834: 		preShutdownHooks:       map[string]preShutdownHookEntry{},
835: 		disabledPostStartHooks: c.DisabledPostStartHooks,
836: 
837: 		healthzRegistry:  healthCheckRegistry{path: "/healthz", checks: c.HealthzChecks},
838: 		livezRegistry:    healthCheckRegistry{path: "/livez", checks: c.LivezChecks, clock: clock.RealClock{}},
839: 		readyzRegistry:   healthCheckRegistry{path: "/readyz", checks: c.ReadyzChecks},
840: 		livezGracePeriod: c.LivezGracePeriod,
841: 
842: 		DiscoveryGroupManager: discovery.NewRootAPIsHandler(c.DiscoveryAddresses, c.Serializer),
843: 
844: 		maxRequestBodyBytes: c.MaxRequestBodyBytes,
845: 
846: 		lifecycleSignals:       c.lifecycleSignals,
847: 		ShutdownSendRetryAfter: c.ShutdownSendRetryAfter,
848: 
849: 		APIServerID:           c.APIServerID,
850: 		StorageReadinessHook:  NewStorageReadinessHook(c.StorageInitializationTimeout),
851: 		StorageVersionManager: c.StorageVersionManager,
852: 
853: 		EffectiveVersion:                        c.EffectiveVersion,
854: 		EmulationForwardCompatible:              c.EmulationForwardCompatible,
855: 		RuntimeConfigEmulationForwardCompatible: c.RuntimeConfigEmulationForwardCompatible,
856: 		FeatureGate:                             c.FeatureGate,
857: 
858: 		muxAndDiscoveryCompleteSignals: map[string]<-chan struct{}{},
859: 	}
860: 
861: 	manager := c.AggregatedDiscoveryGroupManager
862: 	if manager == nil {
863: 		manager = discoveryendpoint.NewResourceManager("apis")
864: 	}
865: 	s.AggregatedDiscoveryGroupManager = manager
866: 	s.AggregatedLegacyDiscoveryGroupManager = discoveryendpoint.NewResourceManager("api")
867: 	for {
