869: 			break
870: 		}
871: 		existing := atomic.LoadInt64(&jsonpatch.AccumulatedCopySizeLimit)
872: 		if existing > 0 && existing < c.JSONPatchMaxCopyBytes {
873: 			break
874: 		}
875: 		if atomic.CompareAndSwapInt64(&jsonpatch.AccumulatedCopySizeLimit, existing, c.JSONPatchMaxCopyBytes) {
876: 			break
877: 		}
878: 	}
