880: 	// first add poststarthooks from delegated targets
881: 	for k, v := range delegationTarget.PostStartHooks() {
882: 		s.postStartHooks[k] = v
883: 	}
884: 
885: 	for k, v := range delegationTarget.PreShutdownHooks() {
